```javascript
export const isArmstrongNumber = (number) => {
  const s = number.toString();
  const p = BigInt(s.length);
  const sum = Array.from(s).reduce((acc, digit) => {
    return acc + BigInt(digit) ** p;
  }, 0n);
  return sum === BigInt(number);
};
```
